import React from "react";
import { motion } from "framer-motion";
import { Link } from "react-scroll";
import { HiArrowRight, HiMail } from "react-icons/hi";
import { FiGithub } from "react-icons/fi";

import profileImg from "../assets/hana.jpg";

const container = {
  hidden: {},
  show: {
    transition: {
      staggerChildren: 0.12,
    },
  },
};

const item = {
  hidden: {
    opacity: 0,
    y: 24,
  },
  show: {
    opacity: 1,
    y: 0,
    transition: {
      duration: 0.65,
      ease: [0.22, 1, 0.36, 1],
    },
  },
};

export default function Hero() {
  return (
    <section
      id="hero"
      className="relative min-h-screen flex items-center overflow-hidden bg-[#050505]"
    >
      {/* Grid */}
      <div
        className="absolute inset-0"
        style={{
          backgroundImage:
            "linear-gradient(rgba(99,102,241,0.05) 1px, transparent 1px), linear-gradient(90deg, rgba(99,102,241,0.05) 1px, transparent 1px)",
          backgroundSize: "70px 70px",
        }}
      />

      {/* Glow */}
      <div className="absolute top-1/4 left-[10%] w-[500px] h-[500px] rounded-full bg-[#4f7cff]/10 blur-[180px]" />
      <div className="absolute bottom-0 right-[10%] w-[500px] h-[500px] rounded-full bg-[#4f7cff]/10 blur-[180px]" />

      <div className="relative max-w-7xl mx-auto px-6 pt-20 w-full">
        <motion.div
          variants={container}
          initial="hidden"
          animate="show"
          className="grid lg:grid-cols-2 gap-20 items-center"
        >
          {/* LEFT */}
          <div>
            <motion.div variants={item} className="mb-8">
              <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-emerald-500/20 bg-emerald-500/10 text-emerald-400 text-sm">
                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                Available for full-time roles
              </span>
            </motion.div>

            <motion.h1
              variants={item}
              className="font-bold leading-[0.9] tracking-tight"
              style={{
                fontSize: "clamp(4rem,8vw,7rem)",
              }}
            >
              <span className="text-white">Hi, I'm</span>

              <br />

              <span className="bg-gradient-to-r from-[#4f7cff] via-[#6c63ff] to-[#8b5cf6] bg-clip-text text-transparent">
                Hana Al
              </span>

              <br />

              <span className="bg-gradient-to-r from-[#4f7cff] via-[#6c63ff] to-[#8b5cf6] bg-clip-text text-transparent">
                Haris
              </span>
            </motion.h1>

            <motion.p
              variants={item}
              className="mt-8 text-[#4f7cff] text-2xl font-medium"
            >
              AI/ML Engineer
            </motion.p>

            <motion.p
              variants={item}
              className="mt-10 text-slate-400 text-xl leading-relaxed max-w-2xl"
            >
              I build production-grade AI systems combining machine learning,
              agentic workflows, and financial intelligence. From AML
              detection engines to LangGraph multi-agent systems, I design
              solutions that reason, adapt, and scale.
            </motion.p>

            {/* Tech pills */}
            <motion.div
              variants={item}
              className="flex flex-wrap gap-3 mt-12"
            >
              {[
                "Python",
                "LangGraph",
                "OpenAI",
                "RAG",
                "FastAPI",
                "PyTorch",
              ].map((tech) => (
                <div
                  key={tech}
                  className="px-5 py-3 rounded-full border border-white/10 bg-white/[0.03] text-white"
                >
                  {tech}
                </div>
              ))}
            </motion.div>

            {/* Buttons */}
            <motion.div
              variants={item}
              className="flex flex-wrap gap-4 mt-14"
            >
              <Link to="projects" smooth duration={500}>
                <button className="px-8 py-4 rounded-xl bg-gradient-to-r from-[#4f7cff] to-[#6c63ff] text-white font-semibold flex items-center gap-2 hover:scale-105 transition">
                  View Projects
                  <HiArrowRight />
                </button>
              </Link>

              <a href="mailto:hanaharis95@gmail.com">
                <button className="px-8 py-4 rounded-xl border border-white/10 text-white flex items-center gap-2 hover:bg-white/5 transition">
                  <HiMail />
                  Contact
                </button>
              </a>

              <a
                href="https://github.com/Hanah7511"
                target="_blank"
                rel="noreferrer"
              >
                <button className="px-8 py-4 rounded-xl border border-white/10 text-white flex items-center gap-2 hover:bg-white/5 transition">
                  <FiGithub />
                  GitHub
                </button>
              </a>
            </motion.div>
          </div>

          {/* RIGHT */}
          <motion.div
            variants={item}
            className="hidden lg:flex justify-center"
          >
            <div className="relative w-[560px] h-[560px]">
              {/* glow */}
              <div className="absolute inset-0 rounded-full bg-[#4f7cff]/20 blur-[120px]" />

              {/* rings */}
              <div className="absolute inset-0 rounded-full border border-[#4f7cff]/20" />
              <div className="absolute inset-5 rounded-full border border-[#4f7cff]/20" />
              <div className="absolute inset-10 rounded-full border border-[#4f7cff]/30" />

              {/* image */}
              <div className="absolute inset-12 rounded-full overflow-hidden border-[5px] border-[#4f7cff]/60 shadow-[0_0_80px_rgba(79,124,255,0.25)]">
                <img
                  src={profileImg}
                  alt="Hana Al Haris"
                  className="w-full h-full object-cover"
                />
              </div>

              {/* badge */}
              <div className="absolute bottom-14 right-2 w-24 h-24 rounded-full bg-[#5f85ff] flex items-center justify-center text-black text-3xl font-bold shadow-2xl">
                HA
              </div>
            </div>
          </motion.div>
        </motion.div>
      </div>
    </section>
  );
}
